RESULT_SET {

  [01] {
    score_name: early_warning_score_aggregate,
    evidence_base: {
      derivation: multicenter_retrospective,
      outcome_measured: deterioration_within_24h,
      variables: [
        heart_rate,
        respiratory_rate,
        systolic_blood_pressure,
        oxygen_saturation,
        temperature,
        level_of_consciousness,
        urine_output
      ],
      weighting: ordinal_deviation_from_normal_range
    },
    validation_cohort: {
      setting: general_medical_ward,
      size: large_multicenter,
      populations: [adult_inpatient, postoperative]
    },
    discharge_threshold: {
      safe_discharge_indicator: all_parameters_within_normal_range_x_12h,
      score_cutoff: low_score_sustained,
      caution_flags: [
        any_single_parameter_extreme,
        upward_trend_over_observation_window
      ]
    }
  },

  [02] {
    score_name: readmission_risk_index,
    evidence_base: {
      derivation: administrative_data_retrospective,
      outcome_measured: 30_day_unplanned_readmission,
      variables: [
        number_of_prior_admissions_12mo,
        length_of_current_stay,
        discharge_disposition,
        comorbidity_burden,
        sodium_at_discharge,
        procedure_complexity
      ],
      weighting: logistic_regression_derived_coefficients
    },
    validation_cohort: {
      setting: academic_and_community_hospitals,
      size: large_administrative_database,
      populations: [general_medicine, cardiology, pulmonology]
    },
    discharge_threshold: {
      low_risk_cutoff: score_below_derived_percentile,
      high_risk_flag: triggers_transitional_care_intervention,
      caution_flags: [
        social_determinants_not_captured,
        index_admission_diagnosis_specific_variation
      ]
    }
  },

  [03] {
    score_name: functional_status_discharge_readiness_scale,
    evidence_base: {
      derivation: prospective_observational,
      outcome_measured: safe_functional_discharge,
      variables: [
        ambulation_independence,
        activities_of_daily_living_score,
        cognitive_baseline_vs_current,
        caregiver_availability,
        medication_self_management_capacity
      ],
      weighting: additive_ordinal
    },
    validation_cohort: {
      setting: general_medicine_and_geriatric_units,
      size: moderate_single_and_multicenter,
      populations: [older_adults, frail_inpatients]
    },
    discharge_threshold: {
      ready_for_discharge: functional_score_at_or_near_baseline,
      requires_placement_planning: score_below_threshold_with_no_caregiver,
      caution_flags: [
        delirium_superimposed_on_dementia,
        fall_risk_elevation
      ]
    }
  },

  [04] {
    score_name: sepsis_recovery_discharge_criteria,
    evidence_base: {
      derivation: expert_consensus_with_retrospective_validation,
      outcome_measured: post_sepsis_safe_discharge,
      variables: [
        fever_resolution_duration,
        lactate_normalization,
        vasopressor_independence_hours,
        oral_intake_tolerance,
        source_control_confirmed,
        antibiotic_oral_step_down_eligibility
      ],
      weighting: threshold_based_checklist
    },
    validation_cohort: {
      setting: medical_icu_stepdown_and_general_ward,
      size: moderate_multicenter,
      populations: [sepsis_survivors, bacteremia_patients]
    },
    discharge_threshold: {
      discharge_eligible: all_criteria_met_x_24h,
      defer_discharge: any_unresolved_criterion,
      caution_flags: [
        immunocompromised_host,
        undrained_infectious_source,
        persistent_organ_dysfunction
      ]
    }
  },

  [05] {
    score_name: heart_failure_discharge_stability_score,
    evidence_base: {
      derivation: prospective_registry_and_rct_subanalysis,
      outcome_measured: 30_day_hf_rehospitalization_or_death,
      variables: [
        weight_change_from_admission,
        natriuretic_peptide_trajectory,
        resting_heart_rate,
        systolic_blood_pressure_at_discharge,
        renal_function_stability,
        oral_diuretic_dose_optimization,
        signs_of_congestion_resolved
      ],
      weighting: composite_threshold_plus_trajectory
    },
    validation_cohort: {
      setting: cardiology_and_general_medicine,
      size: large_multicenter_registry,
      populations: [acute_decompensated_heart_failure]
    },
    discharge_threshold: {
      stable_for_discharge: {
        congestion_resolved: true,
        natriuretic_peptide_direction: downward_trend,
        weight_near_dry_weight: true,
        renal_function: stable_or_improved,
        oral_regimen_tolerated: x_24h
      },
      high_risk_defer: [
        rising_creatinine_on_diuresis,
        persistent_orthopnea,
        natriuretic_peptide_not_trending_down
      ]
    }
  },

  [06] {
    score_name: pneumonia_severity_discharge_index,
    evidence_base: {
      derivation: prospective_multicenter,
      outcome_measured: 30_day_mortality_and_clinical_stability,
      variables: [
        age_numeric,
        nursing_home_residence,
        neoplastic_disease,
        liver_disease,
        congestive_heart_failure,
        cerebrovascular_disease,
        renal_disease,
        altered_mental_status,
        respiratory_rate,
        systolic_blood_pressure,
        temperature,
        pulse,
        arterial_ph,
        blood_urea_nitrogen,
        sodium,
        glucose,
        hematocrit,
        partial_pressure_oxygen,
        pleural_effusion
      ],
      weighting: point_based_regression_derived
    },
    validation_cohort: {
      setting: emergency_department_and_inpatient,
      size: large_multicenter_prospective,
      populations: [community_acquired_pneumonia_adults]
    },
    discharge_threshold: {
      low_risk_class: I_or_II,
      outpatient_eligible: class_I_II,
      inpatient_required: class_III_IV_V,
      clinical_stability_criteria_for_discharge: {
        temperature: below_threshold,
        heart_rate: below_threshold,
        respiratory_rate: below_threshold,
        systolic_bp: above_threshold,
        oxygen_saturation: above_threshold,
        oral_intake: adequate,
        mental_status: at_baseline
      }
    }
  },

  [07] {
    score_name: delirium_resolution_discharge_readiness_index,
    evidence_base: {
      derivation: prospective_observational,
      outcome_measured: post_discharge_adverse_event_from_unresolved_delirium,
      variables: [
        confusion_assessment_method_score,
        duration_of_delirium_episode,
        return_to_cognitive_baseline,
        sleep_wake_cycle_normalization,
        medication_precipitant_removed,
        mobility_restoration
      ],
      weighting: checklist_with_ordinal_severity
    },
    validation_cohort: {
      setting: general_medicine_and_geriatric_wards,
      size: moderate_prospective,
      populations: [older_adults_with_hospital_acquired_delirium]
    },
    discharge_threshold: {
      safe_discharge: {
        delirium_resolved_by_cam: true,
        caregiver_educated: true,
        precipitants_addressed: true,
        mobility_functional_for_setting: true
      },
      defer_or_escalate: [
        hyperactive_delirium_ongoing,
        no_safe_supervision_at_destination,
        new_cognitive_deficit_unexplained
      ]
    }
  },

  [08] {
    score_name: venous_thromboembolism_post_treatment_discharge_score,
    evidence_base: {
      derivation: prospective_cohort_and_rct_data,
      outcome_measured: early_vte_recurrence_and_bleeding_post_discharge,
      variables: [
        clot_burden_severity,
        anticoagulation_initiated_and_tolerated,
        hemodynamic_stability,
        oxygen_requirement_resolved,
        right_heart_strain_markers,
        bleeding_risk_score
      ],
      weighting: risk_stratification_tiered
    },
    validation_cohort: {
      setting: emergency_department_and_inpatient,
      size: large_multicenter,
      populations: [pulmonary_embolism, deep_vein_thrombosis]
    },
    discharge_threshold: {
      low_risk_outpatient_eligible: {
        hemodynamically_stable: true,
        no_right_heart_strain: true,
        anticoagulation_established: true,
        oxygen_saturation_on_room_air: above_threshold,
        reliable_follow_up_confirmed: true
      },
      inpatient_required: [
        intermediate_high_risk_pe,
        active_bleeding,
        renal_failure_affecting_anticoagulant_choice,
        social_barriers_to_outpatient_anticoagulation
      ]
    }
  }

}
